import Foundation

struct CategoryContent11 {
    static let aiVocabulary = CategoryData(
        id: "ai_vocabulary", name: "AI Words to Know", icon: "character.book.closed", colorName: "aiPrimary",
        description: "Learn the language of AI — tokens, models, and more",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 10,
        unlockRequirement: .none
    )

    static let lesson1 = LessonData(id: "av_l1", title: "The Basics", description: "Core AI terms everyone should know", categoryId: "ai_vocabulary", questions: [
        Question(id: "av1_q1", type: .multipleChoice, questionText: "What does 'ML' stand for in the AI world?", options: ["Machine Learning", "Model Language", "Meta Logic", "Memory Layer"], correctAnswer: "Machine Learning", explanation: "ML stands for Machine Learning — the branch of AI where systems improve by learning from data rather than being explicitly programmed with rules."),
        Question(id: "av1_q2", type: .trueFalse, questionText: "Deep learning is a specialized type of machine learning that uses neural networks with many layers.", options: ["True", "False"], correctAnswer: "True", explanation: "Deep learning is a subset of machine learning that uses deep neural networks — networks with multiple hidden layers — to learn complex patterns from large datasets."),
        Question(id: "av1_q3", type: .fillInBlank, questionText: "A neural __________ is a computing system inspired by the biological networks in the human brain.", options: ["network", "pathway", "circuit", "engine"], correctAnswer: "network", explanation: "A neural network is made up of layers of interconnected nodes (artificial neurons) that process information, loosely inspired by how biological neurons work in the brain."),
        Question(id: "av1_q4", type: .matchPairs, questionText: "Match each foundational AI term to its plain-English meaning:", matchPairs: [
            MatchPair(term: "Algorithm", definition: "A step-by-step recipe for solving a problem"),
            MatchPair(term: "Model", definition: "A trained system that can make predictions"),
            MatchPair(term: "Training", definition: "Teaching a system by feeding it data"),
            MatchPair(term: "Inference", definition: "Using a trained model to get answers")
        ], explanation: "These four terms are the bread and butter of AI. Training builds the model, and inference is when you actually use it — like when you ask Claude a question."),
        Question(id: "av1_q5", type: .multipleChoice, questionText: "When you send a message to Claude and get a response, that process is called:", options: ["Inference", "Training", "Fine-tuning", "Backpropagation"], correctAnswer: "Inference", explanation: "Inference is the process of running a trained model to produce outputs. Every time you chat with Claude, Gemini, or ChatGPT, the model is performing inference on your input."),
        Question(id: "av1_q6", type: .scenarioJudgment, questionText: "Your colleague says 'AI and machine learning are exactly the same thing.' Is this accurate?", options: ["No, ML is a subset of AI", "Yes, they mean the same thing", "It depends on the context"], correctAnswer: "No, ML is a subset of AI", explanation: "AI is the broad field of making machines intelligent. Machine learning is one approach within AI — the most popular one today — where systems learn from data. Not all AI uses ML (e.g., rule-based expert systems).")
    ], order: 0, difficulty: .beginner)

    static let lesson2 = LessonData(id: "av_l2", title: "How Models Work", description: "The building blocks inside AI models", categoryId: "ai_vocabulary", questions: [
        Question(id: "av2_q1", type: .multipleChoice, questionText: "In AI, what are 'parameters'?", options: ["The adjustable values a model learns during training", "The questions users ask the model", "The programming languages used to build AI", "The servers that run AI models"], correctAnswer: "The adjustable values a model learns during training", explanation: "Parameters are the internal knobs the model tunes during training. When people say a model has 70 billion parameters, they mean it has 70 billion learned values that shape its behavior."),
        Question(id: "av2_q2", type: .trueFalse, questionText: "A 'token' in AI language models is always exactly one word.", options: ["True", "False"], correctAnswer: "False", explanation: "Tokens are chunks of text, but they do not map neatly to words. A common word like 'hello' might be one token, while a longer word like 'unbelievable' could be split into multiple tokens. Even spaces and punctuation can be tokens."),
        Question(id: "av2_q3", type: .fillInBlank, questionText: "An __________ is a numerical representation that captures the meaning of a word or passage in a format AI models can process.", options: ["embedding", "encoding", "endpoint", "encryption"], correctAnswer: "embedding", explanation: "Embeddings convert text into lists of numbers (vectors) that capture semantic meaning. Words with similar meanings end up with similar embeddings, letting models understand relationships between concepts."),
        Question(id: "av2_q4", type: .matchPairs, questionText: "Match each model-building term to its meaning:", matchPairs: [
            MatchPair(term: "Weights", definition: "Numerical values adjusted during training"),
            MatchPair(term: "Vectors", definition: "Lists of numbers representing data"),
            MatchPair(term: "Layers", definition: "Stacked processing stages in a network"),
            MatchPair(term: "Tensors", definition: "Multi-dimensional arrays of numbers")
        ], explanation: "These are the mathematical building blocks of neural networks. Weights live inside layers, data flows through as tensors, and vectors represent individual pieces of information."),
        Question(id: "av2_q5", type: .sortOrder, questionText: "Put these in order from smallest to largest unit of text processing:", options: ["Token", "Character", "Sentence", "Document"], correctAnswers: ["Character", "Token", "Sentence", "Document"], explanation: "Characters are the smallest units (individual letters). Tokens are typically a few characters or a word. Sentences contain multiple tokens, and documents contain multiple sentences."),
        Question(id: "av2_q6", type: .multipleChoice, questionText: "Why do AI models convert words into numbers (vectors)?", options: ["Because computers can only do math on numbers, not raw text", "Because numbers take up less storage space", "Because users prefer numerical outputs", "Because text is too complicated to store"], correctAnswer: "Because computers can only do math on numbers, not raw text", explanation: "Neural networks are fundamentally mathematical systems. To process language, models must first convert text into numerical representations (embeddings/vectors) that can flow through matrix multiplications and other operations.")
    ], order: 1, difficulty: .beginner)

    static let lesson3 = LessonData(id: "av_l3", title: "Training Talk", description: "How AI models learn and improve", categoryId: "ai_vocabulary", questions: [
        Question(id: "av3_q1", type: .multipleChoice, questionText: "In supervised learning, what does the model learn from?", options: ["Labeled examples with correct answers", "Unlabeled data with no guidance", "Real-time user feedback only", "Random trial and error"], correctAnswer: "Labeled examples with correct answers", explanation: "Supervised learning uses labeled data — input-output pairs where the correct answer is provided. The model learns to map inputs to the right outputs, like learning from a textbook with answer keys."),
        Question(id: "av3_q2", type: .trueFalse, questionText: "Fine-tuning means training a model completely from scratch on new data.", options: ["True", "False"], correctAnswer: "False", explanation: "Fine-tuning starts with an already pre-trained model and adjusts it on a smaller, specialized dataset. It is much cheaper and faster than training from scratch because the model already has broad knowledge."),
        Question(id: "av3_q3", type: .matchPairs, questionText: "Match each training approach to its description:", matchPairs: [
            MatchPair(term: "Supervised Learning", definition: "Learning from labeled examples"),
            MatchPair(term: "Unsupervised Learning", definition: "Finding patterns in unlabeled data"),
            MatchPair(term: "Reinforcement Learning", definition: "Learning through rewards and penalties"),
            MatchPair(term: "Pre-training", definition: "Initial broad training on massive data")
        ], explanation: "Modern LLMs like Claude use a combination: pre-training on vast text data (self-supervised), then fine-tuning with human feedback (reinforcement learning from human feedback, or RLHF)."),
        Question(id: "av3_q4", type: .fillInBlank, questionText: "One complete pass through the entire training dataset is called an __________.", options: ["epoch", "batch", "cycle", "round"], correctAnswer: "epoch", explanation: "An epoch is one full pass through all training data. Models typically train for many epochs, seeing the same data multiple times to gradually improve their performance."),
        Question(id: "av3_q5", type: .multipleChoice, questionText: "What is 'overfitting' in machine learning?", options: ["When a model memorizes training data but fails on new data", "When a model trains for too few epochs", "When a model uses too little data", "When a model runs too slowly"], correctAnswer: "When a model memorizes training data but fails on new data", explanation: "Overfitting is like a student who memorizes test answers but cannot solve new problems. The model performs great on training data but poorly on anything it has not seen before."),
        Question(id: "av3_q6", type: .scenarioJudgment, questionText: "A team has a powerful pre-trained language model but needs it to answer questions about their company's internal documents. What approach makes the most sense?", options: ["Fine-tune the model on company data", "Train a new model from scratch", "Use the model as-is without changes"], correctAnswer: "Fine-tune the model on company data", explanation: "Fine-tuning adapts a pre-trained model to a specific domain. Training from scratch would be vastly more expensive and unnecessary when a strong foundation model already exists. Using it as-is would miss the company-specific knowledge.")
    ], order: 2, difficulty: .intermediate)

    static let lesson4 = LessonData(id: "av_l4", title: "Architecture Speak", description: "The designs behind modern AI systems", categoryId: "ai_vocabulary", questions: [
        Question(id: "av4_q1", type: .multipleChoice, questionText: "What is a 'transformer' in AI?", options: ["A neural network architecture that powers most modern LLMs", "A device that converts electrical voltage", "A type of robot that changes shape", "A data compression algorithm"], correctAnswer: "A neural network architecture that powers most modern LLMs", explanation: "The transformer architecture, introduced in the famous 2017 paper 'Attention Is All You Need,' is the foundation of models like Claude, GPT, Gemini, and Llama. It revolutionized AI with its attention mechanism."),
        Question(id: "av4_q2", type: .trueFalse, questionText: "The 'attention mechanism' helps a model focus on the most relevant parts of its input when generating each piece of output.", options: ["True", "False"], correctAnswer: "True", explanation: "Attention lets the model weigh the importance of different input tokens when producing each output token. For example, when answering a question, it can 'attend to' the most relevant parts of a long passage."),
        Question(id: "av4_q3", type: .fillInBlank, questionText: "A __________ is the simplest form of neural network, consisting of a single artificial neuron that takes inputs, applies weights, and produces an output.", options: ["perceptron", "processor", "predictor", "parameter"], correctAnswer: "perceptron", explanation: "The perceptron, invented in 1958, is the granddaddy of neural networks. It is a single neuron that multiplies inputs by weights, sums them up, and passes the result through an activation function. Modern networks stack millions of these together."),
        Question(id: "av4_q4", type: .matchPairs, questionText: "Match each architecture to what it is best known for:", matchPairs: [
            MatchPair(term: "CNN", definition: "Processing images and visual data"),
            MatchPair(term: "RNN", definition: "Handling sequential data like time series"),
            MatchPair(term: "GAN", definition: "Generating realistic fake images"),
            MatchPair(term: "Transformer", definition: "Powering modern language models")
        ], explanation: "CNNs (Convolutional Neural Networks) excel at vision, RNNs (Recurrent Neural Networks) handle sequences, GANs (Generative Adversarial Networks) create synthetic data, and Transformers dominate language AI."),
        Question(id: "av4_q5", type: .multipleChoice, questionText: "What is a 'diffusion model' in AI?", options: ["A model that generates images by gradually removing noise", "A model that spreads information across a network", "A model that distributes tasks across multiple servers", "A model that slowly degrades over time"], correctAnswer: "A model that generates images by gradually removing noise", explanation: "Diffusion models like those behind DALL-E, Midjourney, and Stable Diffusion work by learning to reverse a noise-adding process. They start with random noise and gradually refine it into a coherent image."),
        Question(id: "av4_q6", type: .sortOrder, questionText: "Put these AI architecture milestones in chronological order:", options: ["Transformer (2017)", "Perceptron (1958)", "CNN for ImageNet (2012)", "GAN (2014)"], correctAnswers: ["Perceptron (1958)", "CNN for ImageNet (2012)", "GAN (2014)", "Transformer (2017)"], explanation: "The perceptron came first in 1958. AlexNet's CNN breakthrough was in 2012, GANs were invented by Ian Goodfellow in 2014, and the transformer architecture was introduced by Google in 2017.")
    ], order: 3, difficulty: .intermediate)

    static let lesson5 = LessonData(id: "av_l5", title: "The Modern Stack", description: "Today's hottest AI terms decoded", categoryId: "ai_vocabulary", questions: [
        Question(id: "av5_q1", type: .multipleChoice, questionText: "What does 'LLM' stand for?", options: ["Large Language Model", "Logical Learning Machine", "Linear Logic Module", "Layered Language Matrix"], correctAnswer: "Large Language Model", explanation: "LLM stands for Large Language Model — a neural network trained on massive amounts of text that can understand and generate human language. Claude, GPT, Gemini, and Llama are all LLMs."),
        Question(id: "av5_q2", type: .fillInBlank, questionText: "RAG stands for Retrieval-Augmented __________, a technique that lets AI models access external knowledge when answering questions.", options: ["Generation", "Grounding", "Grouping", "Governance"], correctAnswer: "Generation", explanation: "RAG combines a retrieval system (that fetches relevant documents) with a generative model (that produces answers). This lets LLMs give accurate, up-to-date answers grounded in specific sources rather than relying solely on training data."),
        Question(id: "av5_q3", type: .trueFalse, questionText: "A 'context window' is the maximum amount of text an AI model can consider at one time during a conversation.", options: ["True", "False"], correctAnswer: "True", explanation: "The context window is like the model's working memory. It includes everything the model can see — your prompt, the conversation history, and any documents provided. Larger context windows let models work with more information at once."),
        Question(id: "av5_q4", type: .matchPairs, questionText: "Match each modern AI concept to its meaning:", matchPairs: [
            MatchPair(term: "Agents", definition: "AI systems that take actions autonomously"),
            MatchPair(term: "Tool Use", definition: "AI calling external functions or APIs"),
            MatchPair(term: "System Prompt", definition: "Hidden instructions that guide AI behavior"),
            MatchPair(term: "MCP", definition: "Model Context Protocol for connecting AI to tools")
        ], explanation: "These are key concepts in modern AI applications. Agents use tool calling to take real actions, system prompts shape behavior, and MCP (Model Context Protocol) standardizes how models connect to external tools and data."),
        Question(id: "av5_q5", type: .scenarioJudgment, questionText: "A developer wants their AI assistant to search the web, query databases, and send emails on behalf of users. Which concept best describes what they need?", options: ["An AI agent with tool use capabilities", "A larger context window", "A better fine-tuned model", "A faster inference speed"], correctAnswer: "An AI agent with tool use capabilities", explanation: "This describes an AI agent — a system that can plan, reason, and take actions using external tools. Tool use (or function calling) lets the AI interact with APIs, databases, and services to accomplish real-world tasks."),
        Question(id: "av5_q6", type: .multipleChoice, questionText: "What is 'function calling' in the context of LLMs?", options: ["The ability of an LLM to request that specific code functions be executed", "The process of calling an LLM's API endpoint", "A way to speed up model inference", "A technique for reducing model size"], correctAnswer: "The ability of an LLM to request that specific code functions be executed", explanation: "Function calling lets an LLM output structured requests to execute specific functions — like searching a database, checking the weather, or sending a message. The model decides which function to call and what arguments to pass.")
    ], order: 4, difficulty: .advanced)

    static let lesson6 = LessonData(id: "av_l6", title: "Hardware & Scale", description: "The engines and economics powering AI", categoryId: "ai_vocabulary", questions: [
        Question(id: "av6_q1", type: .multipleChoice, questionText: "Why are GPUs preferred over CPUs for training AI models?", options: ["GPUs can perform thousands of calculations in parallel", "GPUs are cheaper to manufacture", "GPUs use less electricity", "GPUs have more storage space"], correctAnswer: "GPUs can perform thousands of calculations in parallel", explanation: "GPUs (Graphics Processing Units) were originally designed for rendering graphics, which requires massive parallel computation. Neural network training involves similar parallel math operations, making GPUs ideal for AI workloads."),
        Question(id: "av6_q2", type: .trueFalse, questionText: "A TPU (Tensor Processing Unit) is a custom AI chip designed by Google specifically for machine learning workloads.", options: ["True", "False"], correctAnswer: "True", explanation: "Google developed TPUs (Tensor Processing Units) as application-specific chips optimized for the tensor operations that dominate neural network training and inference. They power many of Google's AI services including Gemini."),
        Question(id: "av6_q3", type: .fillInBlank, questionText: "FLOPS stands for Floating Point Operations Per __________, a measure of computing power.", options: ["Second", "Session", "Sequence", "Set"], correctAnswer: "Second", explanation: "FLOPS measures how many floating-point math operations a chip can perform each second. Modern AI training runs require petaFLOPS (quadrillions of operations per second) or even exaFLOPS of compute."),
        Question(id: "av6_q4", type: .matchPairs, questionText: "Match each hardware term to its role in AI:", matchPairs: [
            MatchPair(term: "GPU", definition: "Parallel processor, workhorse of AI training"),
            MatchPair(term: "TPU", definition: "Google's custom AI accelerator chip"),
            MatchPair(term: "Edge AI", definition: "Running AI directly on local devices"),
            MatchPair(term: "Training Compute", definition: "Total processing power used to train a model")
        ], explanation: "GPUs from NVIDIA dominate AI training, Google builds custom TPUs, edge AI brings models to phones and laptops, and training compute measures the total resources needed to build a model."),
        Question(id: "av6_q5", type: .scenarioJudgment, questionText: "A company wants to run an AI model on smartphones without needing an internet connection. Which concept does this describe?", options: ["On-device AI (edge AI)", "Cloud-based inference", "Distributed training", "Model pre-training"], correctAnswer: "On-device AI (edge AI)", explanation: "On-device or edge AI runs models directly on local hardware like phones, tablets, or laptops. This enables offline use, faster responses, and better privacy since data never leaves the device. Examples include Apple Intelligence and on-device features in Android."),
        Question(id: "av6_q6", type: .sortOrder, questionText: "Rank these from least to most computationally expensive:", options: ["Running inference on a single query", "Fine-tuning a model on custom data", "Training a large model from scratch", "Running a simple rule-based program"], correctAnswers: ["Running a simple rule-based program", "Running inference on a single query", "Fine-tuning a model on custom data", "Training a large model from scratch"], explanation: "Rule-based programs need minimal compute. A single inference query takes a fraction of a second on a GPU. Fine-tuning requires hours to days of GPU time. Training a large model from scratch can cost millions of dollars and take months on thousands of GPUs.")
    ], order: 5, difficulty: .advanced)
}
